   119→      resourceId: validatedBody.resource_link_id,
   120→      userId: validatedBody.user_id,
   121→      roles: validatedBody.roles,
   122→      hasSignature: !!validatedBody.oauth_signature,
   123→      timestamp: validatedBody.oauth_timestamp
   124→    });
