   132→        oauthTimestamp: validatedBody.oauth_timestamp,
   133→        now,
   134→        window: OAUTH_TIMESTAMP_WINDOW
   135→      });
   136→      throw new LtiTimestampError(validatedBody.oauth_timestamp, now);
   137→    }
   138→
   139→    // Step 3: Lookup consumer secret from database or use default
   140→    const consumerKey = validatedBody.oauth_consumer_key;
   141→    let consumerSecret = DEFAULT_CONSUMER_SECRET;
   142→
   143→    // TODO: Implement database lookup for consumer keys (multi-tenant support)
   144→    // For MVP, use default consumer key/secret from environment variables
   145→    if (consumerKey !== DEFAULT_CONSUMER_KEY) {
   146→      // Future: Query lti_consumers table for consumer secret
   147→      logger.warn('Non-default consumer key', { consumerKey });
   148→    }
   149→
   150→    // Step 4: Validate OAuth signature using ims-lti Provider
   151→    // NOTE: For development/testing, you can disable signature validation
   152→    // by setting LTI_DISABLE_SIGNATURE_VALIDATION=true in .env
   153→    const disableValidation = process.env.LTI_DISABLE_SIGNATURE_VALIDATION === 'true';
   154→
   155→    if (!disableValidation) {
   156→      const provider = createProvider(consumerKey, consumerSecret);
   157→
   158→      // The ims-lti library needs the body to have all required OAuth parameters
   159→      // Make sure all required parameters are present
   160→      const requestBody = {
   161→        ...validatedBody,
   162→        oauth_consumer_key: consumerKey,
   163→        oauth_signature: validatedBody.oauth_signature,
   164→        oauth_timestamp: validatedBody.oauth_timestamp,
   165→        oauth_nonce: validatedBody.oauth_nonce,
   166→        oauth_version: validatedBody.oauth_version || '1.0',
   167→        oauth_signature_method: validatedBody.oauth_signature_method || 'HMAC-SHA1'
   168→      };
   169→
   170→      const isValid = await provider.valid_request(requestBody);
   171→
   172→      if (!isValid) {
   173→        logger.error('OAuth signature validation failed', {
   174→          consumerKey,
   175→          contextId: validatedBody.context_id,
   176→          hasSignature: !!validatedBody.oauth_signature,
   177→          timestamp: validatedBody.oauth_timestamp,
   178→          now: Math.floor(Date.now() / 1000)
