   214→/**
   215→ * Parse LTI context from validated launch request
   216→ * Extracts user info, roles, and context identifiers
   217→ */
   218→function parseLtiContext(request: LtiLaunchRequest): LtiContext {
   219→  // Parse roles (comma-separated string → array)
   220→  const roleList = request.roles
   221→    .split(',')
