   225→  // Check if user is instructor (any instructor-like role)
   226→  const isInstructor = roleList.some(role =>
   227→    role.includes('Instructor') ||
   228→    role.includes('TeachingAssistant') ||
   229→    role.includes('Faculty') ||
   230→    role.includes('Staff')
   231→  );
   232→
   233→  return {
   234→    contextKey: `${request.context_id}_${request.resource_link_id}`,
   235→    contextLabel: request.context_label || request.context_title,
   236→    resourceId: request.resource_link_id,
   237→    userId: request.user_id,
   238→    userEmail: request.lis_person_contact_email_primary,
   239→    userFullname: request.lis_person_name_full,
   240→    roles: roleList as LtiRole[],
