   247→// ============================================================================
   248→// Room Lookup / Creation
   249→// ============================================================================
   250→
   251→/**
   252→ * Find or create proctoring room for LTI context
   253→ * Uses lti_context_key for idempotent room creation
   254→ * @param pg - PostgreSQL pool
   255→ * @param context - Parsed LTI context
   256→ * @param examId - Default exam ID (1 for LTI-created rooms)
   257→ * @returns Promise<string> - Room code
   258→ * @throws LtiRoomCreationError - if room creation fails
   259→ */
   260→export async function findOrCreateRoomForLtiContext(
   261→  pg: Pool,
   262→  context: LtiContext,
   263→  examId: number = 1
   264→): Promise<string> {
   265→  const client = await pg.connect();
   266→
   267→  try {
   268→    await client.query('BEGIN');
   269→
   270→    // Step 1: Check if room exists for this LTI context
   271→    const existingRoomResult = await client.query(
   272→      'SELECT id, room_code FROM proctoring_rooms WHERE lti_context_key = $1',
   273→      [context.contextKey]
   274→    );
   275→
   276→    if (existingRoomResult.rows.length > 0) {
   277→      const roomCode = existingRoomResult.rows[0].room_code;
   278→      logger.info('Found existing room for LTI context', {
   279→        contextKey: context.contextKey,
   280→        roomCode
   281→      });
   282→      await client.query('ROLLBACK');
   283→      return roomCode;
   284→    }
   285→
   286→    // Step 2: Create new room for this LTI context
   287→    // NOTE: teacher_id defaults to 1 (admin) - instructor should update via dashboard
   288→    const roomCode = await generateRoomCode();
   289→
   290→    const insertResult = await client.query(
   291→      `INSERT INTO proctoring_rooms (
   292→        exam_id,
   293→        teacher_id,
   294→        room_code,
   295→        status,
   296→        capacity,
   297→        lti_context_key,
   298→        lti_context_label,
   299→        lti_resource_id,
   300→        auto_created
   301→      ) VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
   302→      RETURNING id, room_code`,
   303→      [
   304→        examId, // exam_id (default to 1 for LTI)
   305→        1, // teacher_id (default to admin - instructor should claim ownership)
   306→        roomCode,
   307→        'created', // status
   308→        15, // capacity (default)
   309→        context.contextKey, // lti_context_key
   310→        context.contextLabel || context.contextKey, // lti_context_label
   311→        context.resourceId, // lti_resource_id
   312→        true // auto_created (true = LTI-created)
   313→      ]
   314→    );
   315→
   316→    const newRoomCode = insertResult.rows[0].room_code;
   317→
   318→    logger.info('Created new room for LTI context', {
   319→      contextKey: context.contextKey,
   320→      roomCode: newRoomCode
   321→    });
   322→
   323→    await client.query('COMMIT');
   324→    return newRoomCode;
   325→
   326→  } catch (error: any) {
   327→    await client.query('ROLLBACK');
   328→
   329→    // Check for duplicate key error (race condition - another request created same room)
   330→    if (error.code === '23505') { // unique_violation
   331→      logger.warn('Room already created by another request (race condition)', {
   332→        contextKey: context.contextKey
   333→      });
   334→
   335→      // Retry lookup - room should exist now
   336→      const retryResult = await pg.query(
   337→        'SELECT room_code FROM proctoring_rooms WHERE lti_context_key = $1',
   338→        [context.contextKey]
   339→      );
   340→
   341→      if (retryResult.rows.length > 0) {
   342→        return retryResult.rows[0].room_code;
   343→      }
   344→    }
   345→
   346→    logger.error('Failed to create room for LTI context', {
   347→      contextKey: context.contextKey,
   348→      error
   349→    });
   350→
   351→    throw new LtiRoomCreationError(context.contextKey, error);
   352→  } finally {
   353→    client.release();
   354→  }
   355→}
   356→
   357→/**
   358→ * Generate unique room code (8-char base62)
   359→ * Used for LTI-created rooms
   360→ */
   361→async function generateRoomCode(): Promise<string> {
   362→  const chars = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
   363→  const codeLength = 8;
   364→
   365→  for (let attempt = 0; attempt < 3; attempt++) {
   366→    let code = '';
   367→    for (let i = 0; i < codeLength; i++) {
   368→      code += chars[Math.floor(Math.random() * chars.length)];
   369→    }
   370→
   371→    // Check if code already exists (should be extremely rare)
   372→    // This check is NOT in a transaction - room creation will handle collisions
   373→    // NOTE: We can't check here without a database connection
   374→    // Room creation will retry if there's a collision
   375→
   376→    return code;
   377→  }
   378→
   379→  throw new Error('Failed to generate unique room code after 3 attempts');
   380→}
   381→
   382→// ============================================================================
   383→// User Lookup / Creation
   384→// ============================================================================
   385→
   386→/**
   387→ * Find or create user by email
   388→ * Reuses existing auth logic from room.service.ts
   389→ * @param pg - PostgreSQL pool
   390→ * @param email - User email (from LTI)
   391→ * @param name - User full name (from LTI)
   392→ * @returns Promise<number> - User ID
   393→ */
   394→export async function findOrCreateUserByEmail(
   395→  pg: Pool,
   396→  email: string | undefined,
   397→  name: string | undefined
   398→): Promise<number | null> {
   399→  if (!email) {
   400→    logger.warn('No email in LTI launch - cannot create user');
   401→    return null;
   402→  }
   403→
   404→  try {
   405→    // Check if user exists
   406→    const existingResult = await pg.query(
   407→      'SELECT id FROM users WHERE email = $1',
   408→      [email]
   409→    );
   410→
   411→    if (existingResult.rows.length > 0) {
   412→      logger.info('Found existing user for LTI launch', {
   413→        userId: existingResult.rows[0].id,
   414→        email
   415→      });
   416→      return existingResult.rows[0].id;
   417→    }
   418→
   419→    // Create new user (student role)
   420→    const insertResult = await pg.query(
   421→      `INSERT INTO users (email, name, role) VALUES ($1, $2, 'student')
   422→      RETURNING id`,
   423→      [
   424→        email,
   425→        name || email.split('@')[0] // Use email username if name not provided
   426→      ]
   427→    );
   428→
   429→    logger.info('Created new user for LTI launch', {
   430→      userId: insertResult.rows[0].id,
   431→      email
   432→    });
   433→
   434→    return insertResult.rows[0].id;
   435→
   436→  } catch (error: any) {
   437→    // Handle race condition - user might have been created by another request
   438→    if (error.code === '23505') { // unique_violation
   439→      logger.info('User creation race condition - retrying lookup', { email });
   440→
   441→      const retryResult = await pg.query(
   442→        'SELECT id FROM users WHERE email = $1',
   443→        [email]
   444→      );
   445→
   446→      if (retryResult.rows.length > 0) {
   447→        return retryResult.rows[0].id;
   448→      }
   449→    }
   450→
   451→    logger.error('Failed to create user for LTI launch', {
   452→      email,
   453→      error
   454→    });
   455→
   456→    return null;
   457→  }
   458→}
