   445→function parseCsvLine (line) {
   446→  const values = []
   447→  let currentValue = ''
   448→  let insideQuotes = false
   449→
   450→  for (let index = 0; index < line.length; index += 1) {
   451→    const character = line[index]
   452→    const nextCharacter = line[index + 1]
   453→
   454→    if (character === '"') {
   455→      if (insideQuotes && nextCharacter === '"') {
   456→        currentValue += '"'
   457→        index += 1
   458→        continue
   459→      }
   460→
   461→      insideQuotes = !insideQuotes
   462→      continue
   463→    }
   464→
   465→    if (character === ',' && !insideQuotes) {
   466→      values.push(currentValue)
   467→      currentValue = ''
   468→      continue
   469→    }
   470→
   471→    currentValue += character
   472→  }
   473→
   474→  values.push(currentValue)
   475→  return values.map(value => value.trim())
