### Phase 2: Add JWT Token Validation (1.5 hours)

**2.1 Add token validation endpoint to backend**

File: `backend/src/modules/room/room.routes.ts` (create new route)

```javascript
// POST /api/room/:code/validate-token
// Validates JWT token and returns room/user info
fastify.post('/api/room/:code/validate-token', {
  onRequest: [fastify.authenticate]
}, async (request, reply) => {
  const { code } = request.params;
  const { token } = request.body;

  try {
    // Verify JWT token
    const decoded = jwt.verify(token, process.env.JWT_SECRET || 'dev-secret');

    // Check if token matches this room
    if (decoded.roomCode !== code.toUpperCase()) {
      return reply.code(403).send({
        success: false,
        error: 'Token does not match this room'
      });
    }

    // Check if token is expired
    if (decoded.exp < Date.now() / 1000) {
      return reply.code(403).send({
        success: false,
        error: 'Token has expired'
      });
    }

    // Get room info
    const roomResult = await fastify.pg.query(
      'SELECT id, room_code, capacity, status FROM proctoring_rooms WHERE room_code = $1',
      [code.toUpperCase()]
    );

    if (roomResult.rows.length === 0) {
      return reply.code(404).send({
        success: false,
        error: 'Room not found'
      });
    }

    const room = roomResult.rows[0];

    // Check if room is active
    if (room.status !== 'activated') {
      return reply.code(400).send({
        success: false,
        error: 'Room is not active'
      });
    }

    return reply.send({
      success: true,
      data: {
        roomId: room.id,
        roomCode: room.room_code,
        capacity: room.capacity,
        userId: decoded.userId
      }
    });

  } catch (error) {
    if (error.name === 'JsonWebTokenError') {
      return reply.code(403).send({
        success: false,
        error: 'Invalid token'
      });
    }

    throw error;
  }
});
```

