    return reply.send({
      success: true,
      data: {
        roomId: room.id,
        roomCode: room.room_code,
        capacity: room.capacity,
        currentEnrolled: currentEnrolled,
        userId: decoded.userId
      }
    });

  } catch (error) {
    if (error.name === 'JsonWebTokenError') {
      return reply.code(403).send({
        success: false,
        error: 'Invalid token'
      });
    }

    throw error;
  }
});
