async function validateTokenAndGetRoomInfo(token) {
  try {
    const { apiBaseUrl, headers } = getManualProctoringConfig();

    const response = await fetch(`${apiBaseUrl}/api/room/${roomCode}/validate-token`, {
      method: 'POST',
      headers: {
