  onRequest: [fastify.authenticate, fastify.requireTeacher]
}, async (request, reply) => {
  const { id } = request.params;
  const { capacity } = request.body;
  const teacherId = request.user.id; // From JWT auth

  // Validate capacity
  if (typeof capacity !== 'number' || capacity < 1 || capacity > 100) {
    return reply.code(400).send({
      success: false,
      error: 'Capacity must be between 1 and 100'
    });
  }

  // Verify ownership
  const roomResult = await fastify.pg.query(
    'SELECT teacher_id FROM proctoring_rooms WHERE id = $1',
    [id]
  );

  if (roomResult.rows.length === 0) {
    return reply.code(404).send({
      success: false,
      error: 'Room not found'
    });
  }

  if (roomResult.rows[0].teacher_id !== teacherId) {
    return reply.code(403).send({
      success: false,
      error: 'You do not own this room'
    });
  }

  // Update capacity
  const updateResult = await fastify.pg.query(
    'UPDATE proctoring_rooms SET capacity = $1 WHERE id = $2 RETURNING *',
    [capacity, id]
  );

  return reply.send({
    success: true,
    data: updateResult.rows[0]
  });
});
```

