              padding-top: 20px;
              border-top: 1px solid #e0e0e0;
            }
            .error {
              background: #fee;
              color: #c33;
              padding: 12px;
              border-radius: 6px;
              margin: 20px 0;
            }
          </style>
        </head>
        <body>
          <div class="container">
