   148→// ============================================================================
   149→// API Client
   150→// ============================================================================
   151→
   152→class BackendAPIClient {
   153→  private baseUrl: string;
   154→  private token: string | null = null;
   155→
   156→  constructor(baseUrl: string) {
   157→    this.baseUrl = baseUrl;
   158→    if (typeof window !== 'undefined') {
   159→      this.token = localStorage.getItem('auth_token');
   160→    }
   161→  }
   162→
   163→  setToken(token: string) {
   164→    this.token = token;
   165→    if (typeof window !== 'undefined') {
   166→      localStorage.setItem('auth_token', token);
   167→    }
   168→  }
   169→
   170→  clearToken() {
   171→    this.token = null;
   172→    if (typeof window !== 'undefined') {
   173→      localStorage.removeItem('auth_token');
   174→    }
   175→  }
   176→
   177→  private async request<T>(
   178→    endpoint: string,
   179→    options?: RequestInit
   180→  ): Promise<T> {
   181→    const url = `${this.baseUrl}${endpoint}`;
   182→    const headers = new Headers(options?.headers);
   183→    headers.set('Content-Type', 'application/json');
   184→
   185→    if (this.token) {
   186→      headers.set('Authorization', `Bearer ${this.token}`);
   187→    }
   188→
   189→    const response = await fetch(url, {
   190→      ...options,
   191→      headers,
   192→      credentials: 'include'
   193→    });
   194→
   195→    const data = await response.json().catch(() => ({}));
   196→
   197→    if (!response.ok) {
   198→      const error = data as BackendError;
   199→      throw new Error(error.error || 'Request failed');
   200→    }
   201→
   202→    return data as T;
   203→  }
   204→
   205→  // ==========================================================================
   206→  // Authentication
   207→  // ==========================================================================
   208→
   209→  async login(username: string, password: string): Promise<BackendAuthResponse> {
   210→    const response = await this.request<BackendAuthResponse>('/api/auth/login', {
   211→      method: 'POST',
   212→      body: JSON.stringify({ username, password }),
   213→    });
   214→
   215→    // Store token
   216→    if (response.success && response.data.token) {
   217→      this.setToken(response.data.token);
   218→    }
   219→
   220→    return response;
   221→  }
   222→
   223→  async validateToken(token: string): Promise<BackendAuthResponse> {
   224→    return this.request<BackendAuthResponse>('/api/auth/me', {
   225→      headers: {
   226→        Authorization: `Bearer ${token}`,
   227→      },
   228→    });
   229→  }
   230→
   231→  async getCurrentUser(): Promise<BackendAuthResponse> {
   232→    return this.request<BackendAuthResponse>('/api/auth/me');
