        const room = await roomService.closeRoom(roomId, teacherId);

        return {
          success: true,
          data: {
            roomId: room.id,
            status: room.status
          }
        };
      } catch (error) {
        if ((error as Error).name === 'RoomNotFoundError') {
          return reply.code(404).send({
