            error: 'You are not the owner of this room'
          });
        }

        if ((error as Error).name === 'InvalidStateTransitionError') {
          return reply.code(400).send({
            success: false,
            error: (error as Error).message
          });
        }

        throw error;
      }
    }
  });
});

