  const url = `${BACKEND_URL}/api/lti/launch`;
  const signature = generateOAuthSignature(url, 'POST', baseParams, LTI_CONSUMER_SECRET);

  return {
    url,
    params: {
      ...baseParams,
      oauth_signature: signature
    }
  };
}

